ALTER TABLE content_revisions ADD COLUMN workflow_status ENUM('draft', 'pending_review', 'rejected', 'published', 'unpublished') NOT NULL DEFAULT 'draft' AFTER content, ADD COLUMN submitted_by VARCHAR(36) NULL AFTER created_by, ADD COLUMN submitted_at DATETIME(6) NULL AFTER submitted_by, ADD KEY idx_content_revisions_workflow (model_id, entry_id, workflow_status, revision_number DESC), ADD CONSTRAINT fk_content_revisions_submitter FOREIGN KEY (submitted_by) REFERENCES users (id), ADD CONSTRAINT chk_content_revisions_submission CHECK ((workflow_status = 'draft' AND submitted_by IS NULL AND submitted_at IS NULL) OR (workflow_status <> 'draft' AND submitted_by IS NOT NULL AND submitted_at IS NOT NULL));
